        {
            InvId = (int)(Order.InvId != 0 ? Order.InvId : invId),
            InvNo = Order.InvoiceNo,
            InvDate = DateTime.Now.ToString("yyyy-MM-dd"),
            CreditDays = SelectedCustomer != null && SelectedCustomer.Balance > 0 ? (int)SelectedCustomer.Balance : 0,
            BillAmt = (Order.Items.Sum(x => x.Qty * x.Rate) + Order.TaxAmount - Order.Discount),
            LedgerId = Order.LedgerID != null ? (int)Order.LedgerID : 0,
            MOP = Order.ModeOfPayment,
            VcType = "Sales Order",
            CurrentAmt = (Order.Items.Sum(x => x.Qty * x.Rate) + Order.TaxAmount - Order.Discount),
            SaAmount =0,// (Order.Items.Sum(x => x.Qty * x.Rate) + Order.TaxAmount - Order.Discount),
            VchTypeID = 3,
            SettleStatus = 0
        };
        reqList.Add(req);
        var url = $"{ApiConstants.BaseUrl}/api/Order/LedgerBillStatus";
        var request = new HttpRequestMessage(HttpMethod.Post, url);
        var cdkey = CompanyService.SelectedCompany?.LicenceKey ?? string.Empty;
        var companyCode = CompanyService.SelectedCompany?.CompanyCode ?? string.Empty;
        request.Headers.Add("CdyKey", cdkey);
        request.Headers.Add("CompanyCode", companyCode);
        var token = await TokenService.GetTokenAsync();
        if (!string.IsNullOrWhiteSpace(token))
        {
            request.Headers.Authorization = new System.Net.Http.Headers.AuthenticationHeaderValue("Bearer", token);
        }
        var bodyJson = System.Text.Json.JsonSerializer.Serialize(reqList);
        request.Content = new StringContent(bodyJson, System.Text.Encoding.UTF8, "application/json");
        var response = await Http.SendAsync(request);
        // Optionally handle response
    }

