    protected override async Task OnInitializedAsync()
    {
        InitializeItems();
        await LoadDropdownsAsync();

        // Always load order data after dropdowns are loaded
        if (!string.IsNullOrEmpty(OrderId) && OrderId != "0")
        {
            // If OrderId is present, determine if view or edit mode
            if (IsViewMode || !IsEdit)
            {
                IsViewMode = true;
            }
            var url = $"{ApiConstants.BaseUrl}/api/Order/{OrderId}";
            var cdkey = CompanyService.SelectedCompany?.LicenceKey ?? string.Empty;
            var companyCode = CompanyService.SelectedCompany?.CompanyCode ?? string.Empty;
            var request = new HttpRequestMessage(HttpMethod.Get, url);
            request.Headers.Add("CdyKey", cdkey);
            request.Headers.Add("CompanyCode", companyCode);
            var response = await Http.SendAsync(request);
            if (response.IsSuccessStatusCode)
            {
                var json = await response.Content.ReadAsStringAsync();
                var order = System.Text.Json.JsonSerializer.Deserialize<SalesOrder>(json, new System.Text.Json.JsonSerializerOptions { PropertyNameCaseInsensitive = true });
                if (order != null)
                {
                    Order = order;
                    // Ensure OrderId is set from parameter if missing
                    if (string.IsNullOrEmpty(Order.OrderId))
                    {
                        Order.OrderId = OrderId;
                    }
                    // Try to set InvId from the loaded order if present in JSON
                    if (Order.InvId == 0 && double.TryParse(Order.OrderId, out var parsedInvId))
                    {
                        Order.InvId = parsedInvId;
                    }
                    // Ensure ItemName is set for each item (in case API returns Name instead)
                    if (Order.Items != null)
                    {
                        foreach (var item in Order.Items)
                        {
                            if (!string.IsNullOrEmpty(item.ItemName))
                                item.ItemName = item.ItemName;
                        }
                    }
                    // Set SelectedCustomer fields from loaded Order
                    SelectedCustomer = new Customer
                    {
                        Name = Order.CustomerName,
                        Mobile = Order.MobileNumber,
                        Address = Order.Address,
                        GSTIN = Order.GSTIN,
                        Balance = Order.CustomerBalance
                    };

                    // Set AgentID and PriceListID from loaded Agent/PriceList names
                    if (AgentsList?.Count > 0 && !string.IsNullOrWhiteSpace(Order.Agent))
                        Order.AgentID = AgentsList.FirstOrDefault(a => a.Name == Order.Agent)?.Id ?? 0;
                    if (PriceListsList?.Count > 0 && !string.IsNullOrWhiteSpace(Order.PriceList))
                        Order.PriceListID = PriceListsList.FirstOrDefault(p => p.Name == Order.PriceList)?.Id ?? 0;

                    // Ensure dropdowns display correct values from API response
                    if (SalesmenList?.Count > 0 && !string.IsNullOrWhiteSpace(Order.SalesMan))
                        Order.SalesMan = SalesmenList.FirstOrDefault(s => s.Name == Order.SalesMan)?.Name ?? SalesmenList[0].Name;
                    if (CostCentresList?.Count > 0 && !string.IsNullOrWhiteSpace(Order.CostCentre))
                        Order.CostCentre = CostCentresList.FirstOrDefault(c => c.Name == Order.CostCentre)?.Name ?? CostCentresList[0].Name;
                    if (!string.IsNullOrWhiteSpace(Order.TaxMode) && (Order.TaxMode == "GST" || Order.TaxMode == "Non-GST"))
                        Order.TaxMode = Order.TaxMode;
                    else
                        Order.TaxMode = "GST";
                }
            }
        }
    }

    private async Task LoadDropdownsAsync()
    {
        IsLoadingDropdowns = true;
        try
        {
            var salesmenTask = DropdownService.GetSalesmenAsync();
            var costCentresTask = DropdownService.GetCostCentresAsync();
            var agentsTask = DropdownService.GetAgentsAsync();
            var priceListsTask = DropdownService.GetPriceListsAsync();

            await Task.WhenAll(salesmenTask, costCentresTask, agentsTask, priceListsTask);

            SalesmenList = salesmenTask.Result;
            CostCentresList = costCentresTask.Result;
            AgentsList = agentsTask.Result;
            PriceListsList = priceListsTask.Result;

            await JS.InvokeVoidAsync("console.log", $"Salesmen: {SalesmenList.Count}, CostCentres: {CostCentresList.Count}, Agents: {AgentsList.Count}, PriceLists: {PriceListsList.Count}");

            // Only set defaults if creating a new order (not edit or view mode)
            if (string.IsNullOrEmpty(OrderId) || OrderId == "0")
            {
                if (SalesmenList.Count > 0) Order.SalesMan = SalesmenList[0].Name;
                if (CostCentresList.Count > 0) Order.CostCentre = CostCentresList[0].Name;
                if (AgentsList.Count > 0) Order.Agent = AgentsList[0].Name;
                if (PriceListsList.Count > 0) Order.PriceList = PriceListsList[0].Name;
            }
        }
        catch (Exception ex)
        {
            await JS.InvokeVoidAsync("console.error", "LoadDropdownsAsync error:", ex.Message);
        }
        finally
        {
            IsLoadingDropdowns = false;
        }
    }

