    private async Task OpenCustomerModal()
    {
        ShowCustomerModal = true;
        CustomerSearchQuery = "";
        IsLoadingCustomers = true;
        StateHasChanged();
        try
        {
            var customers = await DropdownService.GetCustomersAsync();
            await JS.InvokeVoidAsync("console.log", $"Customers loaded: {customers.Count}");
            if (customers.Count > 0)
            {
                await JS.InvokeVoidAsync("console.log", $"First customer: Id={customers[0].Id}, Name={customers[0].Name}");
            }
            AllCustomers = customers.Select(c => new Customer
            {
                Name = c.Name,
                Mobile = c.Mobile,
                Address = c.Address,
                GSTIN = c.GSTIN,
                Balance = c.Balance,
                LID = c.LID
            }).ToList();
            FilteredCustomers = AllCustomers;
        }
        catch (Exception ex)
        {
            await JS.InvokeVoidAsync("console.error", "OpenCustomerModal error:", ex.Message);
            AllCustomers = new List<Customer>();
            FilteredCustomers = AllCustomers;
        }
        finally
        {
            IsLoadingCustomers = false;
            StateHasChanged();
        }
    }

