    private void SearchItems(ChangeEventArgs e)
    {
        ItemSearchQuery = e.Value?.ToString() ?? "";
        if (string.IsNullOrEmpty(ItemSearchQuery))
        {
            FilteredItems = AllItems;
        }
        else
        {
            FilteredItems = AllItems.Where(x => 
                x.Name.Contains(ItemSearchQuery, StringComparison.OrdinalIgnoreCase) ||
                x.ItemCode.Contains(ItemSearchQuery, StringComparison.OrdinalIgnoreCase)
            ).ToList();
        }
    }

    private void SearchCustomers(ChangeEventArgs e)
    {
        CustomerSearchQuery = e.Value?.ToString() ?? "";
        if (string.IsNullOrEmpty(CustomerSearchQuery))
        {
            FilteredCustomers = AllCustomers;
        }
        else
        {
            FilteredCustomers = AllCustomers.Where(x =>
                (x.Mobile != null && x.Mobile.Contains(CustomerSearchQuery, StringComparison.OrdinalIgnoreCase)) ||
                (x.Name != null && x.Name.Contains(CustomerSearchQuery, StringComparison.OrdinalIgnoreCase))
            ).ToList();
        }
    }

