            var agentId = AgentMap.TryGetValue(Order.Agent, out var agentid) ? agentid : 0;
            var priceListId = PriceListMap.TryGetValue(Order.PriceList, out var plid) ? plid : 0;
                
            int billTypeId = BillTypeMap.TryGetValue(Order.BillType, out var btid) ? btid : 0;
            int mopId = ModeOfPaymentMap.TryGetValue(Order.ModeOfPayment, out var mopid) ? mopid : 0;
            //int priceListId = Order.PriceListID;
            var amount = Order.Items.Sum(x => x.Qty * x.Rate);

            var salesData = new IBIZWebApp.Models.SalesData
            {
                InvId = isEdit ? Order.InvId : newInvId,
                InvNo = Order.InvoiceNo,
                AutoNum = 0,
                Prefix = "",
                InvDate = Order.Date,
                VchType = "Sales Order",
                MOP = Order.ModeOfPayment,
                TaxModeID = 1,
                LedgerId = Order.LedgerID != null ? (int)Order.LedgerID : 0,
                Party = Order.CustomerName,
                Discount = (double)Order.Discount,
                TaxAmt = (double)Order.TaxAmount,
                GrossAmt = (double)(amount - Order.Discount + Order.TaxAmount),
                BillAmt = (double)(amount - Order.Discount + Order.TaxAmount),
                Cancelled = 0,
                OtherExpense = 0,
                SalesManID = salesManId,
                Taxable = 0,
                NonTaxable = (double)Order.Items.Sum(x => x.Qty * x.Rate),
                ItemDiscountTotal = 0,
                RoundOff = 0,
                UserNarration = string.Empty,
                SortNumber = 0,
                DiscPer = 0,
                VchTypeID = 1,
                CCID = costCentreId,
                CurrencyID = Order.CurrencyID,
                PartyAddress = Order.Address,
                UserID = userId,
                AgentID = agentId,
                CashDiscount = 0,
                DPerType_ManualCalc_Customer = 0,
                NetAmount = (double)Order.Items.Sum(x => x.Qty * x.Rate),
                RefNo = Order.Reference,
                CashPaid = 0,
                CardPaid = 0,
                blnWaitforAuthorisation = 0,
                UserIDAuth = 0,
                BillTime = Order.OrderTime.ToString("HH:mm:ss"),
                StateID = 35,
                ImplementingStateCode = null,
                GSTType = "GSTR1 B2CS",
                CGSTTotal = 0,
                SGSTTotal = 0,
                IGSTTotal = 0,
                PartyGSTIN = Order.GSTIN,
                BillType = Order.BillType,
                blnHold = null,
                PriceListID = priceListId,
                EffectiveDate = Order.Date,
                partyCode = null,
                MobileNo = Order.MobileNumber,
                Email = null,
                TaxType = "None",
                QtyTotal = (double)Order.Items.Sum(x => x.Qty),
                DestCCID = 0,
                AgentCommMode = null,
                AgentCommAmount = 0,
                AgentLID = 0,
                BlnStockInsert = 1,
                BlnConverted = null,
                ConvertedParentVchTypeID = null,
                ConvertedVchTypeID = null,
                ConvertedVchNo = null,
                ConvertedVchID = null,
                DeliveryNoteDetails = null,
                OrderDetails = null,
                IntegrityStatus = null,
                CustomerpointsSettled = null,
                blnCashPaid = null,
                originalsalesinvid = null,
                retuninvid = null,
                returnamount = null,
                SystemName = Environment.MachineName,
                LastUpdateDate = null,
                LastUpdateTime = null,
                DeliveryDetails = string.Empty,
                DespatchDetails = string.Empty,
                TermsOfDelivery = string.Empty,
                FloodCessTot = null,
                CounterID = 0,
                ExtraCharges = null,
                processed = null,
                CessAmountTot = null,
                QtyCompCessAmount = null,
                GiftVoucherNo = null,
                GiftVoucherAmount = null,
                AutoNumRefNo = null,
                AckNo = "0",
                AckDt = null,
                Irn = null,
                SignedInvoice = null,
                SignedQRCode = null,
                Status = null,
                EwbNo = null,
                EwbDt = null,
                EwbValidTill = null,
                Remarks = null,
                EInvoiceIRN = string.Empty,
                StockEffectiveDate = null,
                InTransit = null,
                VsInvDate = null,
                VsEffectiveDate = null,
                PackingList = string.Empty,
                BuyersName = string.Empty,
                PreCarriageBy = string.Empty,
                PlaceOfReceiptBy = string.Empty,
                FlightNo = string.Empty,
                FinalDestination = string.Empty,
                CountryOfDestination = string.Empty,
                PortCode = string.Empty,
                GrowsWeight = string.Empty,
                CountryOfOrigin = string.Empty,
                CurrencyAmt = 0,
                CurrencyRate = 0,
                AppStatus = 0,
                RivInvDate = null,
                ProjectName = string.Empty,
                Projectstatus = 0,
                IsModified = false
            };

            var salesItems = Order.Items.Select((item, idx) => new IBIZWebApp.Models.SalesItemData
            {
                InvID = 0,
                ItemName = item.ItemName,
                ItemId = idx + 1,
                Qty = (double)item.Qty,
                Rate = (double)item.Rate,
                UnitId = 0,
                BatchCode = item.Batch,
                TaxPer = 0,
                TaxAmount = 0,
                Discount = 0,
                MRP = 0,
                SlNo = 0,
                Prate = 0,
                Free = 0,
                ItemDiscount = 0,
                Expiry = null,
                BatchUnique = string.Empty,
                Unit = string.Empty,
                CostValue = 0
            }).ToList();

            var apiModel = new IBIZWebApp.Models.SalesOrderApiModel
            {
                salesOrder = salesData,
                salesOrderItem = salesItems
            };
            var salesOrderJson = System.Text.Json.JsonSerializer.Serialize(apiModel);

            // Debug: Log outgoing JSON
            await JS.InvokeVoidAsync("console.log", "SalesOrder JSON:", salesOrderJson);

            // Pass this JSON string in FilteredJsonData of SalesJsonRequest
            var body = new IBIZWebApp.Models.SalesJsonRequest
            {
                Id = isEdit ? Order.OrderId : string.Empty,
                JsonData = string.Empty,
                FilteredJsonData = salesOrderJson
            };
            var bodyJson = System.Text.Json.JsonSerializer.Serialize(body);
            await JS.InvokeVoidAsync("console.log", "SalesJsonRequest body:", bodyJson);
            request.Content = new StringContent(bodyJson, System.Text.Encoding.UTF8, "application/json");
            var response = await Http.SendAsync(request);
            if (response.IsSuccessStatusCode)
            {
                var result = await response.Content.ReadAsStringAsync();
                SaveSuccess = true;
                      // Call LedgerBillStatusApi only if ModeOfPayment is Credit
        if (Order.ModeOfPayment == "Credit")
            {
                await CallLedgerBillStatusApi(newInvId);
            }
                SaveMessage = isEdit ? "Order updated successfully!" : "Order saved successfully!";
                await JS.InvokeVoidAsync("alert", SaveMessage);
                ClearOrder();
            }
            else
            {
                var error = await response.Content.ReadAsStringAsync();
                SaveSuccess = false;
                SaveMessage = $"Failed to save order: {error}";
                await JS.InvokeVoidAsync("alert", SaveMessage);
            }
        }
        catch (Exception ex)
        {
            SaveSuccess = false;
            SaveMessage = $"Error saving order: {ex.Message}";
            await JS.InvokeVoidAsync("alert", SaveMessage);
        }
    }


    private void ClearOrder()
    {
        Order = new SalesOrder();
        SelectedCustomer = new Customer();
    }

    private void PrintOrder()
    {
        Console.WriteLine("Print order");
    }

    private void CancelOrder()
    {
        if (Order.Items.Count > 0 && !confirm("Are you sure you want to cancel this order?"))
        {
            return;
        }
        Order = new SalesOrder();
        SelectedCustomer = new Customer();
    }

    private bool confirm(string message)
    {
        // In a real app, use a confirmation dialog component
        return true;
    }


    // Add item from API grid to order
    private void AddItemToOrder(SalesItem item)
    {
        var orderItem = new OrderItem
        {
            ItemName = item.Name,
            ItemCode = item.ItemCode,
            Batch = item.Batch,
            Rate = item.Rate,
            Qty = 1
        };
        Order.Items.Add(orderItem);
        StateHasChanged();
    }

